import os

# Function to check if a directory name indicates sensitive information
def is_sensitive_directory(directory_name):
    keywords = ['confidential', 'secret', 'private']
    return any(keyword in directory_name.lower() for keyword in keywords)

# Explore the filesystem from a starting directory
def explore_directory(root_path):
    data_repositories = []

    for dirpath, dirnames, filenames in os.walk(root_path):
        directory_has_sensitive_data = False

        # Check subdirectory names for sensitivity
        for dirname in dirnames:
            dir_full_path = os.path.join(dirpath, dirname)
            if is_sensitive_directory(dirname):
                directory_has_sensitive_data = True

        # Check file permissions and gather relevant file metadata
        file_metadata_list = []
        for filename in filenames:
            try:
                file_path = os.path.join(dirpath, filename)
                file_stats = os.stat(file_path)
                file_permissions = oct(file_stats.st_mode)[-3:]
                file_size = file_stats.st_size
                file_metadata = { 
                    'path': file_path, 
                    'permissions': file_permissions, 
                    'size': file_size
                }
                file_metadata_list.append(file_metadata)
            except OSError:
                continue

        # If sensitive directory or unexpected file permissions, add to repositories
        if directory_has_sensitive_data or any(meta for meta in file_metadata_list if meta['permissions'] in ['777', '775']):
            data_repositories.append({
                'directory': dirpath,
                'files': file_metadata_list
            })

    return data_repositories

# Print results in a human-readable format
def print_data_repositories(data_repositories):
    if data_repositories:
        print("\nIdentified Data Repositories:\n")
        for repo in data_repositories:
            print(f"Directory: {repo['directory']}")
            print("Files:")
            for file_meta in repo['files']:
                print(f"  Path: {file_meta['path']}, Size: {file_meta['size']} bytes, Permissions: {file_meta['permissions']}")
            print("\n" + "-"*50 + "\n")
    else:
        print("No sensitive data repositories found.")

# Example usage
if __name__ == '__main__':
    # Starting point for file system exploration
    root_directory = '/'  # Use '/' for root on Unix-like systems; be careful with Windows
    identified_repositories = explore_directory(root_directory)
    print_data_repositories(identified_repositories)
```

